<?php include 'header.php'; require_admin(); if($_SERVER['REQUEST_METHOD']==='POST'){ $stmt=$pdo->prepare('INSERT INTO products (name,category,brand,price,stock,image,description) VALUES (?,?,?,?,?,?,?)'); $stmt->execute([$_POST['name'],$_POST['category'],$_POST['brand'],$_POST['price'],$_POST['stock'],$_POST['image']?:'assets/images/placeholder.jpg',$_POST['description']]); header('Location: admin.php'); exit;} $products=$pdo->query('SELECT * FROM products ORDER BY id DESC')->fetchAll(); $orders=$pdo->query('SELECT * FROM orders ORDER BY created_at DESC LIMIT 10')->fetchAll(); $users=$pdo->query('SELECT * FROM users ORDER BY created_at DESC LIMIT 10')->fetchAll(); ?>
<section class="section"><h1>Admin Dashboard</h1><div class="stats"><div><strong><?= count($products); ?></strong><span>Products</span></div><div><strong><?= count($orders); ?></strong><span>Recent Orders</span></div><div><strong><?= count($users); ?></strong><span>Recent Users</span></div></div><div class="admin-layout"><form class="form panel" method="POST"><h2>Add Product</h2><input name="name" required placeholder="Product name"><select name="category"><option value="motorcycle">Motorcycle</option><option value="spare_part">Spare Part</option></select><input name="brand" required placeholder="Brand"><input name="price" type="number" step="0.01" required placeholder="Price"><input name="stock" type="number" required placeholder="Stock"><input name="image" placeholder="Image path, e.g. assets/images/bike.jpg"><textarea name="description" placeholder="Description"></textarea><button class="btn">Add Product</button></form><div class="panel"><h2>Recent Orders</h2><?php foreach($orders as $o): ?><p><strong>#<?= $o['id']; ?></strong> <?= htmlspecialchars($o['customer_name']); ?> — $<?= number_format($o['total'],2); ?></p><?php endforeach; ?></div></div><h2>Products</h2><table><tr><th>ID</th><th>Name</th><th>Category</th><th>Price</th><th>Stock</th></tr><?php foreach($products as $p): ?><tr><td><?= $p['id']; ?></td><td><?= htmlspecialchars($p['name']); ?></td><td><?= htmlspecialchars($p['category']); ?></td><td>$<?= number_format($p['price'],2); ?></td><td><?= $p['stock']; ?></td></tr><?php endforeach; ?></table></section><?php include 'footer.php'; ?>
